import {
  Injectable,
  CanActivate,
  ExecutionContext,
  UnauthorizedException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';
import { Request } from 'express';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator';
import { PrismaService } from '../../prisma/prisma.service';
import { ClsService } from 'nestjs-cls';

@Injectable()
export class JwtAuthGuard implements CanActivate {
  constructor(
    private reflector: Reflector,
    private jwtService: JwtService,
    private prisma: PrismaService, // Inject directly (Singleton)
    private cls: ClsService,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    // Verificar si la ruta es pública
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    const request = context.switchToHttp().getRequest();
    const token = this.extractTokenFromHeader(request);

    if (isPublic && !token) {
      return true;
    }

    // Si es público pero HAY token, intentamos procesarlo (Optional Auth)
    // Si falla (expirado, inválido), simplemente lo ignoramos si es público.
    // Si no es público, el error se lanzará más abajo.

    if (!token) {
      throw new UnauthorizedException('Token no proporcionado');
    }

    try {
      const payload = await this.jwtService.verifyAsync(token);

      if (payload.tenantId) {
        // Inyectar contexto multi-tenant de manera segura ANTES de hacer peticiones a Prisma.
        this.cls.set('tenantId', payload.tenantId);
      } else {
        // Log and perhaps throw if tenantId is missing, though we support public maybe.
        console.warn('[JwtAuthGuard] Payload has no tenantId');
      }

      // ✅ User es un modelo global (no scoped por tenant).
      // Se busca por userId (sub del JWT), NO por tenantId.
      // this.prisma.user (sin .secure) es CORRECTO aquí intencionalmente.
      const user = await this.prisma.user.findUnique({
        where: { id: payload.sub },
        select: {
          id: true,
          email: true,
          name: true,
          role: true,
          tenantId: true,
          subscription: {
            select: {
              status: true,
              endDate: true,
            },
          },
        },
      });

      if (!user) {
        throw new UnauthorizedException('Usuario no encontrado');
      }

      // Añadir usuario al request
      request.user = {
        ...user,
        hasActiveSubscription:
          user.subscription?.status === 'ACTIVE' &&
          (!user.subscription?.endDate ||
            new Date(user.subscription.endDate) > new Date()),
      };
    } catch (error) {
      const isExpired =
        error.name === 'TokenExpiredError' ||
        (error.message && error.message.toLowerCase().includes('expired'));

      if (isExpired) {
        // Log expirations as warn/debug since it's expected behavior for client to refresh
        console.warn('[JwtAuthGuard]: Token expired');
      } else {
        console.error('[JwtAuthGuard Error]:', error); // Other errors remain as errors
      }

      if (isPublic) {
        return true;
      }

      if (error instanceof UnauthorizedException) {
        throw error;
      }
      throw new UnauthorizedException(
        `Token inválido o expirado: ${error.message}`,
      );
    }

    return true;
  }

  private extractTokenFromHeader(request: Request): string | undefined {
    // 1. Intentar leer de cookie
    if (request.cookies && request.cookies.accessToken) {
      return request.cookies.accessToken;
    }

    // 2. Intentar leer de header Authorization
    const [type, token] = request.headers.authorization?.split(' ') ?? [];
    return type === 'Bearer' ? token : undefined;
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import { ClsService } from 'nestjs-cls';
import { OrderStatus } from '@alvarosky/database';

// Date Helpers (No dependencies)
function startOfDay(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}

function endOfDay(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate(), 23, 59, 59, 999);
}

function startOfMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), 1);
}

function subDays(d: Date, days: number): Date {
  return new Date(d.getTime() - days * 24 * 60 * 60 * 1000);
}

function formatYMD(d: Date): string {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

@Injectable()
export class AnalyticsService {
  private readonly logger = new Logger(AnalyticsService.name);
  private cache = new Map<string, { data: any; timestamp: number }>();
  private readonly CACHE_TTL = 60000; // 60 seg cache para evitar asfixiar DB

  constructor(
    private readonly prisma: PrismaService,
    private readonly cls: ClsService,
  ) {}

  /** Lee el tenantId del contexto CLS (AsyncLocalStorage). */
  private getTenantId(): string {
    return this.cls.get<string>('tenantId') ?? '';
  }

  async getDashboardStats(period: string = '30d') {
    const tenantId = this.getTenantId();
    const now = new Date();
    const EndDate = endOfDay(now);
    let StartDate = startOfDay(now);

    switch (period) {
      case 'today':
        StartDate = startOfDay(now);
        break;
      case '7d':
        StartDate = startOfDay(subDays(now, 7));
        break;
      case '30d':
        StartDate = startOfDay(subDays(now, 30));
        break;
      case '3m':
        StartDate = startOfDay(subDays(now, 90));
        break;
      case '6m':
        StartDate = startOfDay(subDays(now, 180));
        break;
      default:
        StartDate = startOfDay(subDays(now, 30));
        break;
    }

    const cacheKey = `stats_${tenantId}_${period}`;
    const cached = this.cache.get(cacheKey);
    if (cached && Date.now() - cached.timestamp < this.CACHE_TTL) {
      return cached.data;
    }

    const dateQuery = { gte: StartDate, lte: EndDate };

    // ✅ this.prisma.secure — tenantId se inyecta automáticamente por extensión Prisma
    const [totalRevAgg, totalOrders, periodRevAgg, periodOrdersCount] =
      await Promise.all([
        this.prisma.secure.order.aggregate({
          _sum: { totalAmount: true },
          where: { status: OrderStatus.DELIVERED },
        }),
        this.prisma.secure.order.count({}),
        this.prisma.secure.order.aggregate({
          _sum: { totalAmount: true },
          where: { status: OrderStatus.DELIVERED, createdAt: dateQuery },
        }),
        this.prisma.secure.order.count({ where: { createdAt: dateQuery } }),
      ]);

    const totalRevenue = Number(totalRevAgg._sum?.totalAmount || 0);
    const periodRevenue = Number(periodRevAgg._sum?.totalAmount || 0);

    // Revenue por día — JOINs complejos con GROUP BY DATE() no disponibles en Prisma Client
    const sumByDay: Record<string, number> = {};
    try {
      // eslint-disable-next-line no-restricted-syntax
      const revenueRaw = await this.prisma.$queryRaw<
        { date: Date; total: number }[]
      >`
        SELECT DATE("createdAt") as date, SUM("totalAmount") as total
        FROM "Order"
        WHERE "tenantId" = ${tenantId}
        AND "status" = 'DELIVERED'
        AND "createdAt" >= ${StartDate}
        AND "createdAt" <= ${EndDate}
        GROUP BY DATE("createdAt")
        ORDER BY DATE("createdAt") ASC
      `;
      for (const row of revenueRaw) {
        sumByDay[formatYMD(row.date)] = Number(row.total || 0);
      }
    } catch (e) {
      this.logger.error('Error fetching revenue raw for dashboard', e);
    }

    const revenueByDay: { date: string; total: number }[] = [];
    const diffDays = Math.ceil(
      (EndDate.getTime() - StartDate.getTime()) / (1000 * 3600 * 24),
    );
    for (let i = diffDays; i >= 0; i--) {
      const dStr = formatYMD(subDays(now, i));
      revenueByDay.push({ date: dStr, total: sumByDay[dStr] || 0 });
    }

    // ✅ Distribuciones categóricas — Prisma .secure
    const [
      orderTypeGroup,
      topProductsItems,
      ticketByTypeQuery,
      prodTimesAgg,
      totalUsers,
      recentOrdersRaw,
    ] = await Promise.all([
      this.prisma.secure.order.groupBy({
        by: ['orderType'],
        _count: { id: true },
        _sum: { totalAmount: true },
        where: { createdAt: dateQuery },
      }),
      this.prisma.secure.orderItem.groupBy({
        by: ['productName'],
        _sum: { quantity: true },
        where: {
          order: { createdAt: dateQuery, status: OrderStatus.DELIVERED },
        },
        orderBy: { _sum: { quantity: 'desc' } },
        take: 15,
      }),
      this.prisma.secure.order.groupBy({
        by: ['orderType'],
        _sum: { totalAmount: true },
        _count: { id: true },
        where: { createdAt: dateQuery, status: OrderStatus.DELIVERED },
      }),
      this.prisma.secure.orderDeliveryAnalytics.aggregate({
        _avg: { timeToPrepare: true, timeToShip: true, timeToDeliver: true },
        where: { order: { createdAt: dateQuery } },
      }),
      this.prisma.secure.user.count({}),
      this.prisma.secure.order.findMany({
        where: { createdAt: dateQuery },
        orderBy: { createdAt: 'desc' },
        take: 5,
        select: {
          id: true,
          orderNumber: true,
          customerName: true,
          totalAmount: true,
          status: true,
          orderType: true,
          tableNumber: true,
          createdAt: true,
          _count: { select: { items: true } },
        },
      }),
    ]);

    const orderTypes = orderTypeGroup.map((g) => ({
      type: g.orderType,
      count: g._count.id,
      total: Number(g._sum.totalAmount || 0),
    }));

    const topProducts = topProductsItems.map((p) => ({
      productName: p.productName,
      quantity: p._sum.quantity || 0,
    }));

    const avgTicketByType = ticketByTypeQuery.map((t) => ({
      type: t.orderType,
      avgTicket: t._count.id > 0 ? Number(t._sum.totalAmount) / t._count.id : 0,
    }));

    const productionTimes = [
      {
        stage: 'Preparation',
        minutes: Math.round(prodTimesAgg._avg.timeToPrepare || 0),
      },
      {
        stage: 'Shipping',
        minutes: Math.round(prodTimesAgg._avg.timeToShip || 0),
      },
      {
        stage: 'Delivery',
        minutes: Math.round(prodTimesAgg._avg.timeToDeliver || 0),
      },
    ];

    // Payment methods — queried via order relation (no tenantId manual necesario)
    const paymentGroup = await this.prisma.secure.payment.groupBy({
      by: ['method'],
      _count: { id: true },
      _sum: { amount: true },
      where: { order: { createdAt: dateQuery } },
    });
    const paymentMethods = paymentGroup.map((g) => ({
      method: g.method,
      count: g._count.id,
      total: Number(g._sum.amount || 0),
    }));

    // Production times by product — multi-table JOIN inalcanzable con Prisma ORM
    let productionTimesByProduct: {
      productName: string;
      avgMinutes: number;
    }[] = [];
    try {
      // eslint-disable-next-line no-restricted-syntax
      const prodTimesByProductRaw = await this.prisma.$queryRaw<
        { productName: string; avgMinutes: number }[]
      >`
        SELECT oi."productName", COALESCE(AVG(oda."timeToShip"), 0) as "avgMinutes"
        FROM "OrderItem" oi
        JOIN "OrderDeliveryAnalytics" oda ON oi."orderId" = oda."orderId"
        JOIN "Order" o ON o.id = oi."orderId"
        WHERE o."tenantId" = ${tenantId}
        AND o."createdAt" >= ${StartDate}
        AND o."createdAt" <= ${EndDate}
        AND oda."timeToShip" IS NOT NULL
        GROUP BY oi."productName"
        ORDER BY "avgMinutes" DESC
        LIMIT 10
      `;
      productionTimesByProduct = prodTimesByProductRaw.map((r) => ({
        productName: r.productName,
        avgMinutes: Math.round(Number(r.avgMinutes || 0)),
      }));
    } catch (e) {
      this.logger.error(
        'Error fetching product prod times raw for dashboard',
        e,
      );
    }

    const recentOrders = recentOrdersRaw.map((o) => ({
      id: o.id,
      orderNumber: o.orderNumber,
      customerName: o.customerName,
      totalAmount: Number(o.totalAmount),
      status: o.status,
      orderType: o.orderType,
      tableNumber: o.tableNumber,
      createdAt: o.createdAt.toISOString(),
      itemCount: o._count.items,
    }));

    const result = {
      totalRevenue,
      totalOrders,
      periodRevenue,
      periodOrdersCount,
      revenueByDay,
      orderTypes,
      paymentMethods,
      topProducts,
      avgTicketByType,
      productionTimes,
      productionTimesByProduct,
      recentOrders,
      totalUsers,
      restaurantOrdersToday: periodOrdersCount,
      topProductToday: topProducts[0]?.productName || null,
    };

    this.cache.set(cacheKey, { data: result, timestamp: Date.now() });
    return result;
  }

  async getZReport(dateParam?: string) {
    const tenantId = this.getTenantId();
    const targetDate = dateParam ? new Date(dateParam) : new Date();
    const startObj = startOfDay(targetDate);
    const endObj = endOfDay(targetDate);

    // ✅ El where de tenantId lo inyecta automáticamente .secure
    const ordersWhere = {
      status: OrderStatus.DELIVERED,
      createdAt: { gte: startObj, lte: endObj },
    };

    const [orderCount, salesAgg, paymentGroup] = await Promise.all([
      this.prisma.secure.order.count({ where: ordersWhere }),
      this.prisma.secure.order.aggregate({
        _sum: { totalAmount: true },
        where: ordersWhere,
      }),
      this.prisma.secure.payment.groupBy({
        by: ['method'],
        _sum: { amount: true },
        _count: { id: true },
        where: {
          order: {
            status: OrderStatus.DELIVERED,
            createdAt: { gte: startObj, lte: endObj },
          },
        },
      }),
    ]);

    const totalSales = Number(salesAgg._sum?.totalAmount || 0);
    const avgTicket = orderCount > 0 ? totalSales / orderCount : 0;

    const byMethod = paymentGroup.map((g) => ({
      method: g.method,
      amount: Number(g._sum.amount || 0),
      count: g._count.id,
    }));

    // Desglose por producto: GROUP BY productName + variantId requerido
    // Es imposible replicar este GROUP BY compuesto con Prisma ORM (soporta solo un campo a la vez)
    // eslint-disable-next-line no-restricted-syntax
    const productBreakdown = await this.prisma.$queryRaw<
      {
        productName: string;
        variantId: string;
        variantName: string | null;
        qty: number;
        totalSales: number;
      }[]
    >`
      SELECT
        oi."productName",
        oi."variantId",
        oi."variantName",
        SUM(oi."quantity")::int as qty,
        SUM(oi."price" * oi."quantity")::float as "totalSales"
      FROM "OrderItem" oi
      JOIN "Order" o ON o.id = oi."orderId"
      WHERE o."tenantId" = ${tenantId}
        AND o."status" = 'DELIVERED'
        AND o."createdAt" >= ${startObj}
        AND o."createdAt" <= ${endObj}
      GROUP BY oi."productName", oi."variantId", oi."variantName"
      ORDER BY "totalSales" DESC
    `;

    const variantIds = [...new Set(productBreakdown.map((p) => p.variantId))];

    // Cálculo de costo por porción — JOINs Recipe → RecipeIngredient → InventoryItem
    // No replicable en Prisma ORM (requiere SUM sobre JOIN de 3 tablas con agrupación y NULLIF)

    const recipeCosts =
      variantIds.length > 0
        ? await this.prisma.$queryRaw<
            { variantId: string; costPerPortion: number }[]
          >`
            SELECT
              pv."id" AS "variantId",
              COALESCE(
                SUM(ri."quantity" * ri."wasteFactor" * ii."avgCost") / NULLIF(r."yield", 0),
                0
              )::float AS "costPerPortion"
            FROM "ProductVariant" pv
            JOIN "Recipe" r ON r."productId" = pv."productId"
            JOIN "RecipeIngredient" ri ON ri."recipeId" = r."id"
            JOIN "InventoryItem" ii ON ii."id" = ri."inventoryItemId"
            WHERE pv."id" = ANY(${variantIds})
            GROUP BY pv."id", r."yield"
          `
        : [];

    const costByVariant = new Map<string, number>();
    for (const rc of recipeCosts) {
      costByVariant.set(rc.variantId, rc.costPerPortion);
    }

    let totalCost = 0;
    const productSummary = productBreakdown.map((p) => {
      const unitCost = costByVariant.get(p.variantId) || 0;
      const itemTotalCost = unitCost * p.qty;
      const sales = Number(p.totalSales);
      const margin = sales > 0 ? ((sales - itemTotalCost) / sales) * 100 : 0;
      totalCost += itemTotalCost;

      return {
        productName: p.productName,
        variantName: p.variantName,
        qty: p.qty,
        totalSales: sales,
        unitCost: Math.round(unitCost * 100) / 100,
        totalCost: Math.round(itemTotalCost * 100) / 100,
        margin: Math.round(margin * 10) / 10,
      };
    });

    const totalMargin =
      totalSales > 0
        ? Math.round(((totalSales - totalCost) / totalSales) * 1000) / 10
        : 0;

    return {
      success: true,
      data: {
        totalSales,
        orderCount,
        avgTicket,
        byMethod,
        productSummary,
        totalCost: Math.round(totalCost * 100) / 100,
        totalMargin,
        date: targetDate,
      },
    };
  }
}

import {
  Injectable,
  Logger,
  NotFoundException,
  BadRequestException,
} from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import { Decimal } from '@prisma/client/runtime/library';
import { Prisma, MovementType } from '@alvarosky/database';
import { ClsService } from 'nestjs-cls';
import {
  CreateInventoryItemDto,
  UpdateInventoryItemDto,
  CreateWarehouseDto,
  StockEntryDto,
  StockExitDto,
  StockTransferDto,
} from './dto/inventory.dto';

@Injectable()
export class InventoryService {
  private readonly logger = new Logger(InventoryService.name);

  constructor(
    private prisma: PrismaService,
    private cls: ClsService,
  ) {}

  /** Lee el tenantId del contexto CLS (AsyncLocalStorage). */
  private getTenantId(): string {
    return this.cls.get<string>('tenantId') ?? '';
  }

  // ================================================================
  // WAREHOUSES
  // ================================================================

  // ✅ tenantId eliminado de todas las firmas públicas — .secure lo inyecta
  async createWarehouse(dto: CreateWarehouseDto) {
    if (dto.isDefault) {
      await this.prisma.secure.warehouse.updateMany({
        where: { isDefault: true },
        data: { isDefault: false },
      });
    }

    return this.prisma.secure.warehouse.create({
      data: {
        tenantId: this.getTenantId(),
        name: dto.name,
        isDefault: dto.isDefault ?? false,
      },
    });
  }

  async findAllWarehouses() {
    return this.prisma.secure.warehouse.findMany({
      orderBy: [{ isDefault: 'desc' }, { name: 'asc' }],
      include: { _count: { select: { stock: true } } },
    });
  }

  async getDefaultWarehouse() {
    let warehouse = await this.prisma.secure.warehouse.findFirst({
      where: { isDefault: true },
    });

    if (!warehouse) {
      warehouse = await this.prisma.secure.warehouse.create({
        data: {
          tenantId: this.getTenantId(),
          name: 'Cocina Principal',
          isDefault: true,
        },
      });
      this.logger.log(
        `Auto-created default warehouse for tenant ${this.getTenantId()}`,
      );
    }

    return warehouse;
  }

  async updateWarehouse(id: string, dto: CreateWarehouseDto) {
    const warehouse = await this.prisma.secure.warehouse.findUnique({
      where: { id },
    });
    if (!warehouse) throw new NotFoundException('Almacén no encontrado');

    if (dto.isDefault) {
      await this.prisma.secure.warehouse.updateMany({
        where: { isDefault: true, id: { not: id } },
        data: { isDefault: false },
      });
    }

    return this.prisma.secure.warehouse.update({
      where: { id },
      data: { name: dto.name, isDefault: dto.isDefault },
    });
  }

  async deleteWarehouse(id: string) {
    const warehouse = await this.prisma.secure.warehouse.findUnique({
      where: { id },
      include: { _count: { select: { stock: true, movements: true } } },
    });
    if (!warehouse) throw new NotFoundException('Almacén no encontrado');
    if (warehouse.isDefault) {
      throw new BadRequestException(
        'No se puede eliminar el almacén por defecto',
      );
    }
    if (warehouse._count.stock > 0) {
      throw new BadRequestException(
        'El almacén tiene stock. Transfiera los ingredientes primero.',
      );
    }

    return this.prisma.secure.warehouse.delete({ where: { id } });
  }

  // ================================================================
  // INVENTORY ITEMS (Ingredientes)
  // ================================================================

  async createItem(dto: CreateInventoryItemDto) {
    return this.prisma.secure.inventoryItem.create({
      data: {
        tenantId: this.getTenantId(),
        name: dto.name,
        sku: dto.sku,
        unit: dto.unit ?? 'UN',
        minStock: dto.minStock ?? 0,
        isActive: dto.isActive ?? true,
      },
    });
  }

  async findAllItems(includeInactive = false, take = 100, skip = 0) {
    return this.prisma.secure.inventoryItem.findMany({
      where: { ...(includeInactive ? {} : { isActive: true }) },
      include: {
        stock: {
          include: { warehouse: { select: { id: true, name: true } } },
        },
      },
      orderBy: { name: 'asc' },
      take,
      skip,
    });
  }

  async findOneItem(id: string) {
    const item = await this.prisma.secure.inventoryItem.findUnique({
      where: { id },
      include: {
        stock: {
          include: { warehouse: { select: { id: true, name: true } } },
        },
        movements: {
          orderBy: { createdAt: 'desc' },
          take: 50,
          include: { warehouse: { select: { id: true, name: true } } },
        },
      },
    });
    if (!item) throw new NotFoundException('Ingrediente no encontrado');
    return item;
  }

  async updateItem(id: string, dto: UpdateInventoryItemDto) {
    const item = await this.prisma.secure.inventoryItem.findUnique({
      where: { id },
    });
    if (!item) throw new NotFoundException('Ingrediente no encontrado');

    return this.prisma.secure.inventoryItem.update({
      where: { id },
      data: {
        ...(dto.name !== undefined ? { name: dto.name } : {}),
        ...(dto.sku !== undefined ? { sku: dto.sku } : {}),
        ...(dto.unit !== undefined ? { unit: dto.unit } : {}),
        ...(dto.minStock !== undefined ? { minStock: dto.minStock } : {}),
        ...(dto.isActive !== undefined ? { isActive: dto.isActive } : {}),
      },
    });
  }

  async deleteItem(id: string) {
    const item = await this.prisma.secure.inventoryItem.findUnique({
      where: { id },
      include: {
        stock: { where: { currentStock: { gt: 0 } } },
        ingredients: true,
      },
    });
    if (!item) throw new NotFoundException('Ingrediente no encontrado');
    if (item.ingredients.length > 0) {
      throw new BadRequestException(
        'Este ingrediente está asociado a recetas. Elimine las recetas primero.',
      );
    }

    return this.prisma.secure.inventoryItem.update({
      where: { id },
      data: { isActive: false },
    });
  }

  // ================================================================
  // STOCK MOVEMENTS
  // ================================================================

  async addStockEntry(userId: string, dto: StockEntryDto) {
    // ✅ secure.$transaction — propaga tenant context al tx interno
    return this.prisma.secure.$transaction(async (tx) => {
      const item = await tx.inventoryItem.findUnique({
        where: { id: dto.inventoryItemId },
      });
      if (!item) throw new NotFoundException('Ingrediente no encontrado');

      const warehouse = await tx.warehouse.findUnique({
        where: { id: dto.warehouseId },
      });
      if (!warehouse) throw new NotFoundException('Almacén no encontrado');

      // 1. Crear registro de movimiento
      await tx.inventoryMovement.create({
        data: {
          tenantId: this.getTenantId(),
          inventoryItemId: dto.inventoryItemId,
          warehouseId: dto.warehouseId,
          type: MovementType.ENTRY,
          quantity: dto.quantity,
          unitCost: dto.unitCost,
          reason: dto.reason || 'Entrada manual',
          createdBy: userId,
        },
      });

      // 2. Upsert warehouse stock
      await tx.warehouseStock.upsert({
        where: {
          warehouseId_inventoryItemId: {
            warehouseId: dto.warehouseId,
            inventoryItemId: dto.inventoryItemId,
          },
        },
        create: {
          warehouseId: dto.warehouseId,
          inventoryItemId: dto.inventoryItemId,
          currentStock: dto.quantity,
        },
        update: { currentStock: { increment: dto.quantity } },
      });

      // 3. Recalcular costo promedio ponderado
      const updatedItem = await this.recalculateAvgCost(
        tx,
        dto.inventoryItemId,
        dto.quantity,
        dto.unitCost,
      );

      this.logger.log(
        `Stock entry: +${dto.quantity} ${item.unit} of "${item.name}" to ${warehouse.name}`,
      );

      return updatedItem;
    });
  }

  async addStockExit(userId: string, dto: StockExitDto) {
    return this.prisma.secure.$transaction(async (tx) => {
      const item = await tx.inventoryItem.findUnique({
        where: { id: dto.inventoryItemId },
      });
      if (!item) throw new NotFoundException('Ingrediente no encontrado');

      const warehouseStock = await tx.warehouseStock.findUnique({
        where: {
          warehouseId_inventoryItemId: {
            warehouseId: dto.warehouseId,
            inventoryItemId: dto.inventoryItemId,
          },
        },
      });

      if (
        !warehouseStock ||
        Number(warehouseStock.currentStock) < dto.quantity
      ) {
        throw new BadRequestException(
          `Stock insuficiente de "${item.name}" en este almacén. Disponible: ${warehouseStock?.currentStock ?? 0}`,
        );
      }

      await tx.inventoryMovement.create({
        data: {
          tenantId: this.getTenantId(),
          inventoryItemId: dto.inventoryItemId,
          warehouseId: dto.warehouseId,
          type: MovementType.EXIT,
          quantity: -dto.quantity,
          reason: dto.reason || 'Salida manual',
          createdBy: userId,
        },
      });

      await tx.warehouseStock.update({
        where: {
          warehouseId_inventoryItemId: {
            warehouseId: dto.warehouseId,
            inventoryItemId: dto.inventoryItemId,
          },
        },
        data: { currentStock: { decrement: dto.quantity } },
      });

      this.logger.log(
        `Stock exit: -${dto.quantity} ${item.unit} of "${item.name}"`,
      );
      return { success: true };
    });
  }

  async transferStock(userId: string, dto: StockTransferDto) {
    if (dto.fromWarehouseId === dto.toWarehouseId) {
      throw new BadRequestException(
        'Los almacenes de origen y destino deben ser diferentes',
      );
    }

    return this.prisma.secure.$transaction(async (tx) => {
      const item = await tx.inventoryItem.findUnique({
        where: { id: dto.inventoryItemId },
      });
      if (!item) throw new NotFoundException('Ingrediente no encontrado');

      const sourceStock = await tx.warehouseStock.findUnique({
        where: {
          warehouseId_inventoryItemId: {
            warehouseId: dto.fromWarehouseId,
            inventoryItemId: dto.inventoryItemId,
          },
        },
      });

      if (!sourceStock || Number(sourceStock.currentStock) < dto.quantity) {
        throw new BadRequestException(
          `Stock insuficiente en el almacén de origen. Disponible: ${sourceStock?.currentStock ?? 0}`,
        );
      }

      await tx.inventoryMovement.createMany({
        data: [
          {
            tenantId: this.getTenantId(),
            inventoryItemId: dto.inventoryItemId,
            warehouseId: dto.fromWarehouseId,
            type: MovementType.TRANSFER,
            quantity: -dto.quantity,
            reason: dto.reason || 'Traspaso entre almacenes',
            createdBy: userId,
          },
          {
            tenantId: this.getTenantId(),
            inventoryItemId: dto.inventoryItemId,
            warehouseId: dto.toWarehouseId,
            type: MovementType.TRANSFER,
            quantity: dto.quantity,
            reason: dto.reason || 'Traspaso entre almacenes',
            createdBy: userId,
          },
        ],
      });

      await tx.warehouseStock.update({
        where: {
          warehouseId_inventoryItemId: {
            warehouseId: dto.fromWarehouseId,
            inventoryItemId: dto.inventoryItemId,
          },
        },
        data: { currentStock: { decrement: dto.quantity } },
      });

      await tx.warehouseStock.upsert({
        where: {
          warehouseId_inventoryItemId: {
            warehouseId: dto.toWarehouseId,
            inventoryItemId: dto.inventoryItemId,
          },
        },
        create: {
          warehouseId: dto.toWarehouseId,
          inventoryItemId: dto.inventoryItemId,
          currentStock: dto.quantity,
        },
        update: { currentStock: { increment: dto.quantity } },
      });

      this.logger.log(
        `Stock transfer: ${dto.quantity} ${item.unit} of "${item.name}"`,
      );
      return { success: true };
    });
  }

  // ================================================================
  // DEDUCT BY ORDER (called from OrdersService)
  // ================================================================

  async deductByOrder(
    tenantId: string, // ⚠️ Mantenido temporalmente: InventoryService es llamado desde OrdersService que lo pasa explícitamente
    orderId: string,
    items: Array<{ productId: string; quantity: number }>,
    tx?: any,
  ) {
    // Usar el tx seguro si viene de una transacción, o el cliente secure propio
    const prismaClient = tx || this.prisma.secure;
    const defaultWarehouse = await this.getDefaultWarehouseId(prismaClient);

    const productIds = items.map((i) => i.productId);

    type RecipeWithIngredients = {
      productId: string;
      yield: number;
      ingredients: Array<{
        inventoryItemId: string;
        quantity: any;
        wasteFactor: any;
        inventoryItem: { name: string; minStock: any };
      }>;
    };

    const recipes: RecipeWithIngredients[] = await prismaClient.recipe.findMany(
      {
        where: { productId: { in: productIds } },
        include: {
          ingredients: {
            include: {
              inventoryItem: { select: { name: true, minStock: true } },
            },
          },
        },
      },
    );

    const recipeMap = new Map<string, RecipeWithIngredients>(
      recipes.map((r) => [r.productId, r]),
    );

    const deductions: Array<{
      inventoryItemId: string;
      deductQty: number;
      itemName: string;
      minStock: number;
    }> = [];

    for (const orderItem of items) {
      const recipe = recipeMap.get(orderItem.productId);
      if (!recipe) continue;

      const portionMultiplier = orderItem.quantity / recipe.yield;

      for (const ing of recipe.ingredients) {
        deductions.push({
          inventoryItemId: ing.inventoryItemId,
          deductQty:
            Number(ing.quantity) * Number(ing.wasteFactor) * portionMultiplier,
          itemName: ing.inventoryItem.name,
          minStock: Number(ing.inventoryItem.minStock),
        });
      }
    }

    if (deductions.length === 0) return { alerts: [] };

    const movementData = deductions.map((d) => ({
      tenantId,
      inventoryItemId: d.inventoryItemId,
      warehouseId: defaultWarehouse,
      type: MovementType.SALE,
      quantity: -d.deductQty,
      reason: `Venta orden ${orderId}`,
      reference: orderId,
    }));

    await prismaClient.inventoryMovement.createMany({ data: movementData });

    // Batch upsert — INSERT...ON CONFLICT no replicable en Prisma ORM (no existe upsertMany)
    const aggregated = new Map<string, number>();
    for (const d of deductions) {
      aggregated.set(
        d.inventoryItemId,
        (aggregated.get(d.inventoryItemId) || 0) + d.deductQty,
      );
    }

    const { randomUUID } = await import('crypto');
    const fragments = Array.from(aggregated.entries()).map(
      ([itemId, qty]) =>
        Prisma.sql`(${randomUUID()}, ${defaultWarehouse}, ${itemId}, ${-qty}, CURRENT_TIMESTAMP)`,
    );

    // eslint-disable-next-line no-restricted-syntax
    await prismaClient.$executeRaw`
      INSERT INTO "WarehouseStock" ("id", "warehouseId", "inventoryItemId", "currentStock", "updatedAt")
      VALUES ${Prisma.join(fragments)}
      ON CONFLICT ("warehouseId", "inventoryItemId")
      DO UPDATE SET
        "currentStock" = "WarehouseStock"."currentStock" + EXCLUDED."currentStock",
        "updatedAt" = CURRENT_TIMESTAMP
    `;

    // Low-stock check — HAVING sobre MAX/SUM en JOIN no disponible en Prisma ORM
    const uniqueItemIds = [
      ...new Set(deductions.map((d) => d.inventoryItemId)),
    ];

    const lowStockRows: Array<{
      id: string;
      name: string;
      total_stock: number;
      min_stock: number;
    }> = await prismaClient.$queryRaw`
      SELECT ii."id", ii."name",
             COALESCE(SUM(ws."currentStock"), 0)::float AS total_stock,
             ii."minStock"::float AS min_stock
      FROM "InventoryItem" ii
      LEFT JOIN "WarehouseStock" ws ON ws."inventoryItemId" = ii."id"
      WHERE ii."id" = ANY(${uniqueItemIds})
        AND ii."minStock" > 0
        AND ii."tenantId" = ${tenantId}
      GROUP BY ii."id", ii."name", ii."minStock"
      HAVING COALESCE(SUM(ws."currentStock"), 0) <= ii."minStock"
    `;

    const alerts = lowStockRows.map((r) => ({
      itemName: r.name,
      currentStock: r.total_stock,
      minStock: r.min_stock,
    }));

    if (alerts.length > 0) {
      this.logger.warn(
        `⚠️ Stock bajo: ${alerts.map((a) => `${a.itemName} (${a.currentStock}/${a.minStock})`).join(', ')}`,
      );
    }

    return { alerts };
  }

  // ================================================================
  // RESTORE STOCK (on order cancellation)
  // ================================================================

  async restoreByOrder(tenantId: string, orderId: string, tx?: any) {
    const prismaClient = tx || this.prisma.secure;

    const movements = await prismaClient.inventoryMovement.findMany({
      where: { reference: orderId, type: MovementType.SALE },
    });

    if (movements.length === 0) return;

    await prismaClient.inventoryMovement.createMany({
      data: movements.map((m) => ({
        tenantId,
        inventoryItemId: m.inventoryItemId,
        warehouseId: m.warehouseId,
        type: MovementType.ADJUSTMENT,
        quantity: Math.abs(Number(m.quantity)),
        reason: `Cancelación orden ${orderId}`,
        reference: orderId,
      })),
    });

    await Promise.all(
      movements.map((m) => {
        const restoreQty = Math.abs(Number(m.quantity));
        return prismaClient.warehouseStock.upsert({
          where: {
            warehouseId_inventoryItemId: {
              warehouseId: m.warehouseId,
              inventoryItemId: m.inventoryItemId,
            },
          },
          create: {
            warehouseId: m.warehouseId,
            inventoryItemId: m.inventoryItemId,
            currentStock: restoreQty,
          },
          update: { currentStock: { increment: restoreQty } },
        });
      }),
    );

    this.logger.log(`Stock restaurado por cancelación de orden ${orderId}`);
  }

  // ================================================================
  // LOW STOCK ALERTS
  // ================================================================

  async getLowStockItems() {
    const tenantId = this.getTenantId();
    // SUM + LEFT JOIN + HAVING COALESCE — imposible en Prisma ORM (groupBy no soporta HAVING con aggregate)
    // eslint-disable-next-line no-restricted-syntax
    return this.prisma.$queryRaw<
      Array<{
        id: string;
        name: string;
        unit: string;
        minStock: number;
        totalStock: number;
      }>
    >`
      SELECT
        ii."id",
        ii."name",
        ii."unit",
        ii."minStock"::float AS "minStock",
        COALESCE(SUM(ws."currentStock"), 0)::float AS "totalStock"
      FROM "InventoryItem" ii
      LEFT JOIN "WarehouseStock" ws ON ws."inventoryItemId" = ii."id"
      WHERE ii."tenantId" = ${tenantId}
        AND ii."isActive" = true
        AND ii."minStock" > 0
      GROUP BY ii."id", ii."name", ii."unit", ii."minStock"
      HAVING COALESCE(SUM(ws."currentStock"), 0) <= ii."minStock"
      ORDER BY (COALESCE(SUM(ws."currentStock"), 0) / NULLIF(ii."minStock", 0)) ASC
      LIMIT 50
    `;
  }

  // ================================================================
  // COSTING HELPERS
  // ================================================================

  async getRecipeCost(productId: string) {
    const recipe = await this.prisma.secure.recipe.findUnique({
      where: { productId },
      select: { id: true, yield: true },
    });
    if (!recipe) return null;

    // JOIN de 3 tablas con cálculo de línea de costo — no replicable en Prisma ORM
    // eslint-disable-next-line no-restricted-syntax
    const breakdown = await this.prisma.$queryRaw<
      Array<{
        ingredient: string;
        quantity: number;
        unit: string;
        unitCost: number;
        lineCost: number;
      }>
    >`
      SELECT
        ii."name" AS "ingredient",
        ri."quantity"::float AS "quantity",
        ii."unit",
        ii."avgCost"::float AS "unitCost",
        (ri."quantity" * ri."wasteFactor" * ii."avgCost")::float AS "lineCost"
      FROM "RecipeIngredient" ri
      JOIN "InventoryItem" ii ON ii."id" = ri."inventoryItemId"
      WHERE ri."recipeId" = ${recipe.id}
    `;

    const totalCost = breakdown.reduce((sum, b) => sum + b.lineCost, 0);
    const costPerPortion = totalCost / recipe.yield;

    return {
      productId,
      yield: recipe.yield,
      totalCost,
      costPerPortion,
      breakdown,
    };
  }

  async getAllProductsCostOptimized() {
    const tenantId = this.getTenantId();
    // SUM sobre JOIN + CASE + GROUP BY compuesto — requiere raw SQL
    // eslint-disable-next-line no-restricted-syntax
    return this.prisma.$queryRaw<
      Array<{
        productId: string;
        productName: string;
        salePrice: number;
        totalCost: number;
        costPerPortion: number;
        margin: number;
        recipeYield: number;
      }>
    >`
      SELECT
        p."id" AS "productId",
        p."name" AS "productName",
        p."basePrice"::float AS "salePrice",
        SUM(ri."quantity" * ri."wasteFactor" * ii."avgCost")::float AS "totalCost",
        (SUM(ri."quantity" * ri."wasteFactor" * ii."avgCost") / r."yield")::float AS "costPerPortion",
        CASE
          WHEN p."basePrice" > 0
          THEN ((p."basePrice" - (SUM(ri."quantity" * ri."wasteFactor" * ii."avgCost") / r."yield"))
                / p."basePrice" * 100)::float
          ELSE 0
        END AS "margin",
        r."yield"::int AS "recipeYield"
      FROM "Recipe" r
      JOIN "Product" p ON p."id" = r."productId"
      JOIN "RecipeIngredient" ri ON ri."recipeId" = r."id"
      JOIN "InventoryItem" ii ON ii."id" = ri."inventoryItemId"
      WHERE p."tenantId" = ${tenantId}
      GROUP BY p."id", p."name", p."basePrice", r."yield"
      ORDER BY "margin" ASC
    `;
  }

  async getDashboardMetrics() {
    const tenantId = this.getTenantId();
    // Los tres queries usan CTE y HAVING que son irremplazables en Prisma ORM
    const [lowStockCount, avgMargin, topExpensiveIngredients] =
      await Promise.all([
        // eslint-disable-next-line no-restricted-syntax
        this.prisma.$queryRaw<[{ count: number }]>`
        SELECT COUNT(*)::int AS "count"
        FROM (
          SELECT ii."id"
          FROM "InventoryItem" ii
          LEFT JOIN "WarehouseStock" ws ON ws."inventoryItemId" = ii."id"
          WHERE ii."tenantId" = ${tenantId}
            AND ii."isActive" = true
            AND ii."minStock" > 0
          GROUP BY ii."id"
          HAVING COALESCE(SUM(ws."currentStock"), 0) <= ii."minStock"
        ) sub
      `,
        // eslint-disable-next-line no-restricted-syntax
        this.prisma.$queryRaw<[{ avg_margin: number | null }]>`
        WITH product_margins AS (
          SELECT
            p."id",
            CASE WHEN p."basePrice" > 0
            THEN ((p."basePrice" - (SUM(ri."quantity" * ri."wasteFactor" * ii."avgCost") / r."yield"))
                  / p."basePrice" * 100)
            ELSE 0 END AS margin
          FROM "Recipe" r
          JOIN "Product" p ON p."id" = r."productId"
          JOIN "RecipeIngredient" ri ON ri."recipeId" = r."id"
          JOIN "InventoryItem" ii ON ii."id" = ri."inventoryItemId"
          WHERE p."tenantId" = ${tenantId}
          GROUP BY p."id", p."basePrice", r."yield"
        )
        SELECT AVG(margin)::float AS "avg_margin"
        FROM product_margins
      `,
        // eslint-disable-next-line no-restricted-syntax
        this.prisma.$queryRaw<
          Array<{
            name: string;
            unit: string;
            totalConsumed: number;
            totalValue: number;
          }>
        >`
        SELECT
          ii."name",
          ii."unit",
          ABS(SUM(im."quantity"))::float AS "totalConsumed",
          (ABS(SUM(im."quantity")) * ii."avgCost")::float AS "totalValue"
        FROM "InventoryMovement" im
        JOIN "InventoryItem" ii ON ii."id" = im."inventoryItemId"
        WHERE im."tenantId" = ${tenantId}
          AND im."type" = 'SALE'
          AND im."createdAt" >= NOW() - INTERVAL '30 days'
        GROUP BY ii."id", ii."name", ii."unit", ii."avgCost"
        ORDER BY "totalValue" DESC
        LIMIT 5
      `,
      ]);

    return {
      lowStockCount: lowStockCount[0]?.count ?? 0,
      avgMargin: avgMargin[0]?.avg_margin ?? 0,
      topExpensiveIngredients,
    };
  }

  // ================================================================
  // PRIVATE HELPERS
  // ================================================================

  private async recalculateAvgCost(
    tx: any,
    inventoryItemId: string,
    newQuantity: number,
    newUnitCost: number,
  ) {
    const item = await tx.inventoryItem.findUnique({
      where: { id: inventoryItemId },
      include: { stock: true },
    });

    if (!item) throw new NotFoundException('Item not found');

    const currentTotalStock = item.stock.reduce(
      (sum: number, s: any) => sum + Number(s.currentStock),
      0,
    );
    const oldTotalValue =
      (currentTotalStock - newQuantity) * Number(item.avgCost);
    const newTotalValue = newQuantity * newUnitCost;
    const newAvgCost =
      currentTotalStock > 0
        ? (oldTotalValue + newTotalValue) / currentTotalStock
        : newUnitCost;

    return tx.inventoryItem.update({
      where: { id: inventoryItemId },
      data: {
        avgCost: Math.round(newAvgCost * 10000) / 10000,
        lastCost: newUnitCost,
      },
    });
  }

  private async getDefaultWarehouseId(prismaClient: any): Promise<string> {
    const warehouse = await prismaClient.warehouse.findFirst({
      where: { isDefault: true },
      select: { id: true },
    });

    if (!warehouse) {
      const created = await prismaClient.warehouse.create({
        data: {
          tenantId: this.getTenantId(),
          name: 'Cocina Principal',
          isDefault: true,
        },
      });
      return created.id;
    }

    return warehouse.id;
  }
